const ethers = require('ethers');

// You should replace this with your own RPC URL and Private Key
let url = 'http://localhost:8545';  // Your Infura RPC Url or Ganache local development chain
let key = '';  // Your Ethereum wallet private key, remember to use metamask to generate it.

// Setup the provider using ethers.js
let provider = new ethers.providers.JsonRpcProvider(url);
provider.getNetwork().then((network) => { console.log('Connected to network:', network.name, 'id:', network.chainId)} );

// Setup the wallet and signer using ethers.js
let wallet = new ethers.Wallet(key).connect(provider);

async function sendTransaction() {
    const tx = await wallet.sendTransaction({ to: '', value: ethers.utils.parseEther('') }); // Enter the smart contract address and transaction amount
    console.log("Waiting for transaction to be mined...", tx.hash);
    
    tx.wait().then((receipt) => { 
        if(receipt.status === 1){console.log('Transaction was successful!');} 
        else{console.log('Failed to send transaction.')}}
    );
}
sendTransaction();